    update_time = sysdate()
where connection_code = #{connectionCode}
  and sync_batch_id <> #{syncBatchId}

mapper.select:
select c.connection_code, conn.system_kind, conn.master_warehouse_name, c.master_sku, c.master_product_name, c.product_alias_name, c.approve_status, c.product_type, c.product_description, c.image_url, c.main_code, c.other_code, c.fnsku, c.country_of_origin_name, c.currency_code, c.customhouse_code, c.dangerous_cargo, c.declare_name_cn, c.declare_name_en, c.declare_price, c.product_height, c.product_height_bs, c.product_length, c.product_length_bs, c.product_weight, c.product_weight_bs, c.product_width, c.product_width_bs, c.wms_height, c.wms_height_bs, c.wms_length, c.wms_length_bs, c.wms_weight, c.wms_weight_bs, c.wms_width, c.wms_width_bs, c.cat1_name, c.cat2_name, c.cat3_name, c.platform_sku_info_json, c.brazil_tax_info_json, c.source_payload_hash, c.status, c.search_text, c.sync_batch_id, c.first_seen_time, c.last_seen_time, c.update_time, case when p.sku_pairing_id is null then 'UNASSIGNED' else 'PAIRED' end as pairing_status, p.sku_pairing_id, p.system_sku, p.system_sku_name, p.customer_name from upstream_system_sku_candidate c inner join upstream_system_connection conn on conn.connection_code = c.connection_code left join upstream_system_sku_pairing p on p.connection_code = c.connection_code and p.master_sku = c.master_sku where 1 = 1
and c.connection_code = #{connectionCode}
and ( conn.system_kind = #{systemKind}
or conn.system_kind = 'LINGXING_WMS'
)
and conn.master_warehouse_name like concat('%', #{masterWarehouseName}, '%')
and c.master_sku like concat('%', #{masterSku}, '%')
and ( c.master_product_name like concat('%', #{productName}, '%') or c.product_alias_name like concat('%', #{productName}, '%') or c.product_description like concat('%', #{productName}, '%') )
and ( c.main_code like concat('%', #{identifyCodeKeyword}, '%') or c.other_code like concat('%', #{identifyCodeKeyword}, '%') or c.fnsku like concat('%', #{identifyCodeKeyword}, '%') )
and ( c.cat1_name like concat('%', #{categoryKeyword}, '%') or c.cat2_name like concat('%', #{categoryKeyword}, '%') or c.cat3_name like concat('%', #{categoryKeyword}, '%') )
and c.approve_status = #{approveStatus}
and c.dangerous_cargo = #{dangerousCargo}
and c.status = #{status}
and p.sku_pairing_id is not null
and p.sku_pairing_id is null
and ( c.search_text like concat('%', #{keyword}, '%') or c.connection_code like concat('%', #{keyword}, '%') or conn.master_warehouse_name like concat('%', #{keyword}, '%') or p.system_sku like concat('%', #{keyword}, '%') or p.system_sku_name like concat('%', #{keyword}, '%') or p.customer_name like concat('%', #{keyword}, '%') )
order by c.update_time desc, c.master_sku asc

select *
from upstream_system_sku_candidate
where connection_code = #{connectionCode}
  and master_sku = #{masterSku}
limit 1

